using System.Net;using System.Net.Http.Json;using DBH.UnitTest.Shared;namespace DBH.UnitTest.UnitTests;/// <summary>/// Bad case: Try to upload file to non-existent EHR/// Expected: 404 Not Found/// </summary>public class EhrServiceTests_AddEhrFile_WithNonExistentEhr_ShouldReturnNotFound : ApiTestBase{    protected override IReadOnlyCollection<string> RequiredServices => new[]    {        "AuthService",        "EhrService"    };    [SkippableFact]    public async Task AddEhrFile_WithNonExistentEhr_ShouldReturnNotFound()    {        await AuthenticateAsDoctorAsync(EhrClient);        var fakeEhrId = Guid.NewGuid();                using var fileContent = new MultipartFormDataContent();        var fileData = new ByteArrayContent(new byte[] { 1, 2, 3, 4, 5 });        fileContent.Add(fileData, "file", "test-file.txt");        var response = await EhrClient.PostAsync(            ApiEndpoints.Ehr.AddFile(fakeEhrId),             fileContent);        Assert.True(            response.StatusCode == HttpStatusCode.NotFound ||             response.StatusCode == HttpStatusCode.BadRequest,            $"Expected 404 or 400, got {response.StatusCode}");    }}